using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n,x[100810],y[100810],v[100810],a,b,c,d;
double s,an=0,r[100810];
double f(int i,int j)
{
	return sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
}
void dfs(int t)
{
	if(t==n)
	{
		an=max(an,s);
		return;
	}
	FOR(i,1,n)
	{
		if(v[i])continue;
		double l1=x[i]-min(a,c);
		double l2=max(a,c)-x[i];
		double l3=y[i]-min(b,d);
		double l4=max(b,d)-y[i];
		double mn=min({l1,l2,l3,l4});
		FOR(j,1,n)
		{
			if(v[j]&&j!=i)
			{
				double dd=f(i,j);
				double tmp=dd-r[j];
				mn=min(mn,tmp);
			}
		}
		mn=max(mn,0.0);
		s+=mn*mn*3.1415926;
		v[i]=1;
		r[i]=mn;
		dfs(t+1);
		r[i]=0;
		s-=mn*mn*3.1415926;
		v[i]=0;
	}
}
signed main(void)
{
	cin>>n;
	cin>>a>>b>>c>>d;
	if(a<c)swap(a,c);
	if(b<d)swap(b,d);
	FOR(i,1,n)cin>>x[i]>>y[i];
	dfs(0);
	double ar=(max(a,c)-min(a,c))*(max(b,d)-min(b,d));
	an=ar-an;
	int res=(int)(an+0.5);
	cout<<res;
	return false;
}
